def _peak_to_rms(curve: np.ndarray) -> float:
    """Peak value divided by RMS of the curve (excluding the peak itself).

    High = peaked surface (trust the argmax).  Low = flat.  NaN-safe.
    """
    c = np.asarray(curve, dtype=float)
    c = c[np.isfinite(c)]
    if c.size < 3:
        return float("nan")
    peak = float(c.max())
    # Remove the peak bin and take RMS of the rest
    rest = np.sort(c)[:-1]
    rms = math.sqrt(float((rest ** 2).mean())) if rest.size > 0 else float("nan")
    if rms <= 0 or not np.isfinite(rms):
        return float("nan")
    return peak / rms

